import { describe, it, expect, beforeEach, vi } from 'vitest';
import { AnalyticsService } from '../../src/services/analytics.service.js';
import type { AnalyticsRepository, AggregatedMetric } from '../../src/repositories/analytics.repository.js';
import type { AnalyticsQuery, DateRange, TimeSeriesPoint } from '../../src/models/analytics.js';
import { calculateChangePercent, calculateTrend } from '../../src/models/analytics.js';

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function makeDateRange(startIso = '2026-01-01', endIso = '2026-01-31'): DateRange {
  return { start: new Date(startIso), end: new Date(endIso) };
}

function makeQuery(overrides: Partial<AnalyticsQuery> = {}): AnalyticsQuery {
  return {
    dateRange: makeDateRange(),
    granularity: 'day',
    ...overrides,
  };
}

function makeAggregated(total: number, previousTotal: number): AggregatedMetric {
  return { total, previousTotal, timeSeries: [] };
}

function makeMockRepo(overrides: Partial<AnalyticsRepository> = {}): AnalyticsRepository {
  return {
    countOrders: vi.fn().mockReturnValue(makeAggregated(100, 80)),
    sumRevenue: vi.fn().mockReturnValue(makeAggregated(5000, 4000)),
    countNewUsers: vi.fn().mockReturnValue(makeAggregated(50, 40)),
    getTimeSeries: vi.fn().mockReturnValue([]),
    getRecentActivity: vi.fn().mockReturnValue([]),
    ...overrides,
  } as unknown as AnalyticsRepository;
}

// ---------------------------------------------------------------------------
// Pure helper function tests
// ---------------------------------------------------------------------------

describe('calculateChangePercent', () => {
  it('calculates percentage change correctly', () => {
    expect(calculateChangePercent(120, 100)).toBe(20);
  });

  it('returns 100 when previous is 0 and current is positive', () => {
    expect(calculateChangePercent(50, 0)).toBe(100);
  });

  it('returns 0 when both current and previous are 0', () => {
    expect(calculateChangePercent(0, 0)).toBe(0);
  });

  it('handles negative change', () => {
    expect(calculateChangePercent(80, 100)).toBe(-20);
  });

  it('handles large multiplier changes', () => {
    expect(calculateChangePercent(1000, 10)).toBe(9900);
  });
});

describe('calculateTrend', () => {
  it('returns "up" for positive change above threshold', () => {
    expect(calculateTrend(1)).toBe('up');
    expect(calculateTrend(50)).toBe('up');
  });

  it('returns "down" for negative change below threshold', () => {
    expect(calculateTrend(-1)).toBe('down');
    expect(calculateTrend(-50)).toBe('down');
  });

  it('returns "flat" for change within threshold', () => {
    expect(calculateTrend(0)).toBe('flat');
    expect(calculateTrend(0.5)).toBe('flat');
    expect(calculateTrend(-0.5)).toBe('flat');
  });
});

// ---------------------------------------------------------------------------
// AnalyticsService
// ---------------------------------------------------------------------------

describe('AnalyticsService', () => {
  let repo: ReturnType<typeof makeMockRepo>;
  let service: AnalyticsService;

  beforeEach(() => {
    repo = makeMockRepo();
    service = new AnalyticsService(repo as unknown as AnalyticsRepository);
  });

  // -----------------------------------------------------------------------
  // getMetric
  // -----------------------------------------------------------------------

  describe('getMetric', () => {
    it('returns a MetricSummary for orders', () => {
      const result = service.getMetric('orders', makeDateRange(), 'day');

      expect(result.metricType).toBe('orders');
      expect(result.current).toBe(100);
      expect(result.previous).toBe(80);
      expect(result.changePercent).toBe(25); // (100-80)/80 * 100
      expect(result.trend).toBe('up');
      expect(repo.countOrders).toHaveBeenCalledOnce();
    });

    it('returns a MetricSummary for revenue', () => {
      const result = service.getMetric('revenue', makeDateRange(), 'day');

      expect(result.metricType).toBe('revenue');
      expect(result.current).toBe(5000);
      expect(result.previous).toBe(4000);
      expect(result.changePercent).toBe(25);
      expect(repo.sumRevenue).toHaveBeenCalledOnce();
    });

    it('returns a MetricSummary for users', () => {
      const result = service.getMetric('users', makeDateRange(), 'day');

      expect(result.metricType).toBe('users');
      expect(result.current).toBe(50);
      expect(result.previous).toBe(40);
      expect(repo.countNewUsers).toHaveBeenCalledOnce();
    });

    it('computes conversion as orders/users', () => {
      const result = service.getMetric('conversion', makeDateRange(), 'day');

      expect(result.metricType).toBe('conversion');
      // 100 orders / 50 users = 2
      expect(result.current).toBe(2);
      // 80 orders / 40 users = 2
      expect(result.previous).toBe(2);
    });

    it('handles conversion when users is zero', () => {
      repo.countNewUsers = vi.fn().mockReturnValue(makeAggregated(0, 0));

      const result = service.getMetric('conversion', makeDateRange(), 'day');

      expect(result.current).toBe(0);
      expect(result.previous).toBe(0);
    });

    it('includes time series data from the repository', () => {
      const ts: TimeSeriesPoint[] = [
        { timestamp: new Date('2026-01-01'), value: 10 },
        { timestamp: new Date('2026-01-02'), value: 20 },
      ];
      repo.getTimeSeries = vi.fn().mockReturnValue(ts);

      const result = service.getMetric('orders', makeDateRange(), 'day');

      expect(result.timeSeries).toEqual(ts);
    });

    it('passes the correct granularity to the repository', () => {
      service.getMetric('orders', makeDateRange(), 'week');
      expect(repo.getTimeSeries).toHaveBeenCalledWith('orders', expect.any(Object), 'week');
    });

    it('handles zero previous value (100% change)', () => {
      repo.countOrders = vi.fn().mockReturnValue(makeAggregated(50, 0));

      const result = service.getMetric('orders', makeDateRange(), 'day');

      expect(result.changePercent).toBe(100);
      expect(result.trend).toBe('up');
    });

    it('handles both values being zero (flat)', () => {
      repo.countOrders = vi.fn().mockReturnValue(makeAggregated(0, 0));

      const result = service.getMetric('orders', makeDateRange(), 'day');

      expect(result.changePercent).toBe(0);
      expect(result.trend).toBe('flat');
    });

    it('reports downward trend when current < previous', () => {
      repo.countOrders = vi.fn().mockReturnValue(makeAggregated(60, 100));

      const result = service.getMetric('orders', makeDateRange(), 'day');

      expect(result.changePercent).toBe(-40);
      expect(result.trend).toBe('down');
    });
  });

  // -----------------------------------------------------------------------
  // getDashboard
  // -----------------------------------------------------------------------

  describe('getDashboard', () => {
    it('returns all four metric categories', () => {
      const result = service.getDashboard(makeQuery());

      expect(result.metrics.orders).toBeDefined();
      expect(result.metrics.revenue).toBeDefined();
      expect(result.metrics.users).toBeDefined();
      expect(result.metrics.conversion).toBeDefined();
    });

    it('includes the queried dateRange', () => {
      const range = makeDateRange('2026-03-01', '2026-03-31');
      const result = service.getDashboard(makeQuery({ dateRange: range }));

      expect(result.dateRange).toBe(range);
    });

    it('sets generatedAt to a recent Date', () => {
      const before = new Date();
      const result = service.getDashboard(makeQuery());
      const after = new Date();

      expect(result.generatedAt.getTime()).toBeGreaterThanOrEqual(before.getTime());
      expect(result.generatedAt.getTime()).toBeLessThanOrEqual(after.getTime());
    });

    it('includes recent activity', () => {
      repo.getRecentActivity = vi.fn().mockReturnValue([
        { type: 'order_created', entityId: 'ord-1', timestamp: new Date() },
        { type: 'user_created', entityId: 'usr-1', timestamp: new Date() },
      ]);

      const result = service.getDashboard(makeQuery());

      expect(result.recentActivity).toHaveLength(2);
      expect(result.recentActivity[0].id).toBe('activity-0');
      expect(result.recentActivity[0].description).toContain('ord-1');
      expect(result.recentActivity[1].description).toContain('usr-1');
    });

    it('handles empty recent activity', () => {
      const result = service.getDashboard(makeQuery());

      expect(result.recentActivity).toEqual([]);
    });
  });

  // -----------------------------------------------------------------------
  // getReportSummary
  // -----------------------------------------------------------------------

  describe('getReportSummary', () => {
    it('returns totals for orders, revenue, and new users', () => {
      const result = service.getReportSummary(makeQuery());

      expect(result.totals.orders).toBe(100);
      expect(result.totals.revenue).toBe(5000);
      expect(result.totals.newUsers).toBe(50);
    });

    it('computes average order value correctly', () => {
      const result = service.getReportSummary(makeQuery());

      // 5000 revenue / 100 orders = 50
      expect(result.totals.averageOrderValue).toBe(50);
    });

    it('returns 0 average order value when orders is 0', () => {
      repo.countOrders = vi.fn().mockReturnValue(makeAggregated(0, 0));

      const result = service.getReportSummary(makeQuery());

      expect(result.totals.averageOrderValue).toBe(0);
    });

    it('includes topMetrics with orders, revenue, and users', () => {
      const result = service.getReportSummary(makeQuery());

      expect(result.topMetrics).toHaveLength(3);
      expect(result.topMetrics.map(m => m.metricType)).toEqual([
        'orders',
        'revenue',
        'users',
      ]);
    });

    it('includes the date range and generatedAt', () => {
      const range = makeDateRange('2026-02-01', '2026-02-28');
      const result = service.getReportSummary(makeQuery({ dateRange: range }));

      expect(result.dateRange).toBe(range);
      expect(result.generatedAt).toBeInstanceOf(Date);
    });
  });

  // -----------------------------------------------------------------------
  // Activity description formatting
  // -----------------------------------------------------------------------

  describe('activity descriptions', () => {
    it('formats order_created description', () => {
      repo.getRecentActivity = vi.fn().mockReturnValue([
        { type: 'order_created', entityId: 'ord-42', timestamp: new Date() },
      ]);

      const result = service.getDashboard(makeQuery());
      expect(result.recentActivity[0].description).toBe('New order created: ord-42');
    });

    it('formats order_status_changed description', () => {
      repo.getRecentActivity = vi.fn().mockReturnValue([
        { type: 'order_status_changed', entityId: 'ord-7', timestamp: new Date() },
      ]);

      const result = service.getDashboard(makeQuery());
      expect(result.recentActivity[0].description).toBe('Order status updated: ord-7');
    });

    it('formats user_created description', () => {
      repo.getRecentActivity = vi.fn().mockReturnValue([
        { type: 'user_created', entityId: 'usr-99', timestamp: new Date() },
      ]);

      const result = service.getDashboard(makeQuery());
      expect(result.recentActivity[0].description).toBe('New user registered: usr-99');
    });
  });

  // -----------------------------------------------------------------------
  // Edge cases with large datasets
  // -----------------------------------------------------------------------

  describe('large dataset edge cases', () => {
    it('handles very large metric values', () => {
      repo.sumRevenue = vi.fn().mockReturnValue(makeAggregated(1_000_000_000, 999_000_000));

      const result = service.getMetric('revenue', makeDateRange(), 'day');

      expect(result.current).toBe(1_000_000_000);
      expect(result.changePercent).toBeCloseTo(0.1001, 2);
    });

    it('handles many activity entries', () => {
      const entries = Array.from({ length: 100 }, (_, i) => ({
        type: 'order_created' as const,
        entityId: `ord-${i}`,
        timestamp: new Date(),
      }));
      repo.getRecentActivity = vi.fn().mockReturnValue(entries);

      const result = service.getDashboard(makeQuery());
      expect(result.recentActivity).toHaveLength(100);
      expect(result.recentActivity[99].id).toBe('activity-99');
    });
  });
});

